(window.webpackJsonp=window.webpackJsonp||[]).push([[1368],{1300:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> smallestRange = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> N=nums.length\\n  <span class=\\"hljs-keyword\\">let</span> aux=<span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">let</span> pqMin=<span class=\\"hljs-keyword\\">new</span> PriorityQueue(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>]&lt;<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">let</span> max=-<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;aux.length;i++){\\n    max=<span class=\\"hljs-built_in\\">Math</span>.max(max,nums[i][aux[i]])\\n    pqMin.insert([nums[i][aux[i]],i])\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> rangeLen=<span class=\\"hljs-literal\\">Infinity</span>,rangeStart=<span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">while</span>(!pqMin.isEmpty()){\\n    <span class=\\"hljs-keyword\\">let</span> [min,id]=pqMin.delMin()\\n    <span class=\\"hljs-keyword\\">if</span>(max-min&lt;rangeLen){\\n      rangeLen=max-min\\n      rangeStart=min\\n    }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(max-min===rangeLen){\\n      <span class=\\"hljs-keyword\\">if</span>(min&lt;rangeStart)rangeStart=min\\n    }\\n    aux[id]++\\n    <span class=\\"hljs-keyword\\">if</span>(aux[id]==nums[id].length)<span class=\\"hljs-keyword\\">break</span>\\n    max=<span class=\\"hljs-built_in\\">Math</span>.max(max,nums[id][aux[id]])\\n    pqMin.insert([nums[id][aux[id]],id])\\n   \\n  }\\n  <span class=\\"hljs-keyword\\">return</span> [rangeStart,rangeStart+rangeLen]\\n};\\n\\n<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">PriorityQueue</span>(<span class=\\"hljs-params\\">compareFunction</span>)</span>{\\n  <span class=\\"hljs-keyword\\">let</span> heap=[<span class=\\"hljs-literal\\">null</span>]\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swim</span>(<span class=\\"hljs-params\\">idx</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(idx&lt;<span class=\\"hljs-number\\">2</span>)<span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">let</span> k=<span class=\\"hljs-built_in\\">Math</span>.floor(idx/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span>(compareFunction(heap[idx],heap[k])){\\n      swap(heap,idx,k)\\n      idx=k\\n      swim(idx)\\n    }\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">sink</span>(<span class=\\"hljs-params\\">idx</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> k=<span class=\\"hljs-built_in\\">Math</span>.floor(idx*<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span>(k&gt;=heap.length)<span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span>(k&lt;heap.length &amp;&amp; heap[k+<span class=\\"hljs-number\\">1</span>] &amp;&amp; compareFunction(heap[k+<span class=\\"hljs-number\\">1</span>],heap[k])) k++\\n    <span class=\\"hljs-keyword\\">if</span>(compareFunction(heap[k],heap[idx])){\\n      swap(heap,idx,k)\\n      idx=k\\n      sink(idx)\\n    }\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swap</span>(<span class=\\"hljs-params\\">arr,i,j</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> temp=arr[i]\\n    arr[i]=arr[j]\\n    arr[j]=temp\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.insert=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\">v</span>) </span>{\\n    heap.push(v)\\n    swim(heap.length<span class=\\"hljs-number\\">-1</span>)\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.delMin=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    swap(heap,<span class=\\"hljs-number\\">1</span>,heap.length<span class=\\"hljs-number\\">-1</span>)\\n    <span class=\\"hljs-keyword\\">let</span> min=heap.pop()\\n    sink(<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">return</span> min\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.min=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap[<span class=\\"hljs-number\\">1</span>]\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.isEmpty=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length===<span class=\\"hljs-number\\">1</span>\\n  }\\n}\\n</code></pre>\\n"],"titleSlug":"smallest-range-covering-elements-from-k-lists","hasThinking":false,"content":"<p>\u4f60\u6709\xa0<code>k</code>\xa0\u4e2a <strong>\u975e\u9012\u51cf\u6392\u5217</strong> \u7684\u6574\u6570\u5217\u8868\u3002\u627e\u5230\u4e00\u4e2a <strong>\u6700\u5c0f </strong>\u533a\u95f4\uff0c\u4f7f\u5f97\xa0<code>k</code>\xa0\u4e2a\u5217\u8868\u4e2d\u7684\u6bcf\u4e2a\u5217\u8868\u81f3\u5c11\u6709\u4e00\u4e2a\u6570\u5305\u542b\u5728\u5176\u4e2d\u3002</p>\\n\\n<p>\u6211\u4eec\u5b9a\u4e49\u5982\u679c\xa0<code>b-a < d-c</code>\xa0\u6216\u8005\u5728\xa0<code>b-a == d-c</code>\xa0\u65f6\xa0<code>a < c</code>\uff0c\u5219\u533a\u95f4 <code>[a,b]</code> \u6bd4 <code>[c,d]</code> \u5c0f\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [[4,10,15,24,26], [0,9,12,20], [5,18,22,30]]\\n<strong>\u8f93\u51fa\uff1a</strong>[20,24]\\n<strong>\u89e3\u91ca\uff1a</strong> \\n\u5217\u8868 1\uff1a[4, 10, 15, 24, 26]\uff0c24 \u5728\u533a\u95f4 [20,24] \u4e2d\u3002\\n\u5217\u8868 2\uff1a[0, 9, 12, 20]\uff0c20 \u5728\u533a\u95f4 [20,24] \u4e2d\u3002\\n\u5217\u8868 3\uff1a[5, 18, 22, 30]\uff0c22 \u5728\u533a\u95f4 [20,24] \u4e2d\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [[1,2,3],[1,2,3],[1,2,3]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [[10,10],[11,11]]\\n<strong>\u8f93\u51fa\uff1a</strong>[10,11]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [[10],[11]]\\n<strong>\u8f93\u51fa\uff1a</strong>[10,11]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [[1],[2],[3],[4],[5],[6],[7]]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,7]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>nums.length == k</code></li>\\n\\t<li><code>1 <= k <= 3500</code></li>\\n\\t<li><code>1 <= nums[i].length <= 50</code></li>\\n\\t<li><code>-10<sup>5</sup> <= nums[i][j] <= 10<sup>5</sup></code></li>\\n\\t<li><code>nums[i]</code> \u6309\u975e\u9012\u51cf\u987a\u5e8f\u6392\u5217</li>\\n</ul>\\n","title":"632. \u6700\u5c0f\u533a\u95f4","relatedTags":["\u54c8\u5e0c\u8868","\u53cc\u6307\u9488","\u5b57\u7b26\u4e32"],"difficult":"Hard","lang":["javascript"],"uniqueID":"632"}')}}]);